  ('policepromo-8b7f1efc-moex-00015', 'policepromo-8b7f1efc', 'policepromo-8b7f1efc-moex-113-3082b5f1', 'sub-policepromo-8b7f1efc-02', NULL, 'single_choice', '有關公營造物利用關係之敘述，下列何者錯誤？', '["其利用關係，得基於營造物利用規則而生", "其利用型態，得為公法利用關係或私法利用關係", "基於對內有家主權，而得排除檢調或司法人員之進入", "其利用型態，基本上由法規或公營造物主體裁量定之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:25+00:00", "source_pdf_sha1": "d5cbcf5a16ce", "answer_pdf_sha1": "679249538eb6", "source_family": "moex-gov-tw", "moex": {"exam_code": "113170", "c": "101", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法", "year": "113", "exam_name": "113年警察人員升官等考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "policepromo", "civil_category": "行政警察人員"}'::jsonb, NULL),
