  ('policepromo-8b7f1efc-moex-00017', 'policepromo-8b7f1efc', 'policepromo-8b7f1efc-moex-113-3082b5f1', 'sub-policepromo-8b7f1efc-02', NULL, 'single_choice', '依行政罰法規定與我國學理，無論法律或自治條例，均可作為處罰之依據。下列與此相關之敘述，何者錯誤？', '["此處所稱之法律，包括符合授權明確性原則之法規命令", "此處所稱之自治條例，不包括職業團體內部之自治規章", "此處所稱之法律，不包括具有間接對外效力之行政規則", "此處所稱之自治條例，包括與大學自治相關之自治規章"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:25+00:00", "source_pdf_sha1": "d5cbcf5a16ce", "answer_pdf_sha1": "679249538eb6", "source_family": "moex-gov-tw", "moex": {"exam_code": "113170", "c": "101", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法", "year": "113", "exam_name": "113年警察人員升官等考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "policepromo", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('policepromo-8b7f1efc-moex-00018', 'policepromo-8b7f1efc', 'policepromo-8b7f1efc-moex-113-3082b5f1', 'sub-policepromo-8b7f1efc-02', NULL, 'single_choice', '有關公務員責任之敘述，下列何者正確？', '["行政懲處與司法懲戒併行制度違憲", "同一行為，不受懲戒法院二次懲戒", "對懲戒法庭判決不服者，得另向行政法院起訴", "對政務官嚴重違法失職行為，得予以行政懲處"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:25+00:00", "source_pdf_sha1": "d5cbcf5a16ce", "answer_pdf_sha1": "679249538eb6", "source_family": "moex-gov-tw", "moex": {"exam_code": "113170", "c": "101", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法", "year": "113", "exam_name": "113年警察人員升官等考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "policepromo", "civil_category": "行政警察人員"}'::jsonb, NULL)
